class Solution {
    public int minimumLength(String s) {
        int n = s.length();
        int left = 0;
        int right = n - 1;
        while (left < right && s.charAt(left) == s.charAt(left + 1)) {
            left++;
        }
        while (left < right && s.charAt(right) == s.charAt(right - 1)) {
            right--;
        }
        return n - (right - left + 1);
    }
}
